async function main() {
  console.log(`đźŚ± Seeding ${entreprises.length} entreprises...`);

  let created = 0;
  for (const e of entreprises) {
    const referenceSPI = `SPI-${e.secteurActivite.substring(0, 3)}-${String(created + 1).padStart(4, '0')}`;

    await prisma.entreprise.upsert({
      where: { referenceSPI },
      update: {},
      create: {
        ...e,
        referenceSPI,
        adresse: e.ville ? `${e.ville}, Cameroun` : 'Cameroun',
        produitsPrincipaux: JSON.stringify([e.sousSecteur || e.secteurActivite]),
      },
    });
    created++;
    if (created % 10 === 0) {
      console.log(`  â†’ ${created}/${entreprises.length} entreprises crĂ©Ă©es...`);
    }
  }

  console.log(`\nâś… ${created} entreprises crĂ©Ă©es avec succĂ¨s !`);
}

main()
  .catch((e) => {
    console.error('âťŚ Erreur seeding entreprises :', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
